#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import shutil
import subprocess
from datetime import datetime
from pathlib import Path
from typing import Any

import numpy as np
import pandas as pd

from paper_profile_utils import profile_slug_from_config, report_path
from runtime_state_schema import get_runtime_truth

PROJECT_ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = PROJECT_ROOT / "research" / "reports"
DEFAULT_CONFIG_PATH = PROJECT_ROOT / "config" / "strategy_probe_guard_v1.json"


def load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def read_csv(path: Path) -> pd.DataFrame:
    if not path.exists():
        return pd.DataFrame()
    try:
        return pd.read_csv(path)
    except Exception:
        return pd.DataFrame()


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def latest_date_tag(profile_slug: str) -> str:
    pattern = f"paper_{profile_slug}_trading_journal_*.csv" if profile_slug else "paper_trading_journal_*.csv"
    files = sorted(REPORT_DIR.glob(pattern))
    if not files:
        return datetime.now().strftime("%Y%m%d")
    digits = "".join(ch for ch in files[-1].stem if ch.isdigit())
    return digits[-8:] if len(digits) >= 8 else datetime.now().strftime("%Y%m%d")


def annualized_sharpe(series: pd.Series) -> float:
    s = pd.to_numeric(series, errors="coerce").dropna().astype(float)
    if len(s) < 2:
        return 0.0
    vol = float(s.std(ddof=0))
    if vol <= 0:
        return 0.0
    return float(s.mean() / vol * np.sqrt(252.0))


def trailing_return_pct(series: pd.Series) -> float:
    s = pd.to_numeric(series, errors="coerce").dropna().astype(float)
    if s.empty:
        return 0.0
    return round((float((1.0 + s).prod()) - 1.0) * 100.0, 2)


def resolve_openclaw_bin() -> str:
    candidates = [
        shutil.which("openclaw"),
        str(Path.home() / ".local" / "share" / "fnm" / "node-versions" / "v22.22.0" / "installation" / "bin" / "openclaw"),
        "/usr/local/bin/openclaw",
    ]
    for candidate in candidates:
        if candidate and Path(candidate).exists():
            return str(Path(candidate))
    return ""



def push_feishu(cfg: dict[str, Any], message: str) -> tuple[bool, str]:
    feishu = cfg.get("feishu", {}) or {}
    if not feishu.get("enabled", False):
        return False, "feishu_disabled"
    openclaw_bin = resolve_openclaw_bin()
    if not openclaw_bin:
        return False, "openclaw_cli_missing"
    cmd = [
        openclaw_bin,
        "message",
        "send",
        "--channel",
        str(feishu.get("channel", "feishu")),
        "--account",
        str(feishu.get("account", "main")),
        "--target",
        str(feishu.get("target_user", "")),
        "-m",
        message,
    ]
    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=120)
    except Exception as exc:
        return False, f"push_failed:{exc}"
    detail = ((proc.stdout or "").strip() or (proc.stderr or "").strip())[-2000:]
    return proc.returncode == 0, detail


def main() -> None:
    parser = argparse.ArgumentParser(description="模拟盘/探针仓自动停机守卫")
    parser.add_argument("--config", default=str(DEFAULT_CONFIG_PATH))
    parser.add_argument("--date", default="")
    parser.add_argument("--push", action="store_true")
    args = parser.parse_args()

    cfg_path = Path(args.config).resolve()
    cfg = load_json(cfg_path)
    profile_slug = profile_slug_from_config(cfg)
    date_tag = args.date.strip() or latest_date_tag(profile_slug)
    thresholds = cfg.get("thresholds", {}) or {}

    journal_path = report_path(REPORT_DIR, "journal", profile_slug=profile_slug, date_tag=date_tag)
    orders_path = report_path(REPORT_DIR, "orders", profile_slug=profile_slug, date_tag=date_tag)
    account_path = report_path(REPORT_DIR, "account_latest", profile_slug=profile_slug)
    metrics_path = report_path(REPORT_DIR, "metrics", profile_slug=profile_slug, date_tag=date_tag)
    positions_path = report_path(REPORT_DIR, "positions_latest", profile_slug=profile_slug)

    journal_df = read_csv(journal_path)
    orders_df = read_csv(orders_path)
    positions_df = read_csv(positions_path)
    account_payload = load_json(account_path)
    metrics_payload = load_json(metrics_path)
    metrics = metrics_payload.get("metrics", {}) or {}
    # T05: Per-panel runtime risk truth — use panel-specific file if available
    panel_risk_path = REPORT_DIR / f"runtime_risk_state_latest_{profile_slug}.json"
    if panel_risk_path.exists():
        runtime_state_path = panel_risk_path
    else:
        runtime_state_path = REPORT_DIR / "runtime_risk_state_latest.json"
    runtime_payload = load_json(runtime_state_path)
    runtime_truth = get_runtime_truth(runtime_payload)

    runtime_truth_state = str(runtime_truth.get("state") or "")
    runtime_trading_status = str(runtime_truth.get("trading_status") or "")
    runtime_buy_authorized = bool(runtime_truth.get("buy_authorized")) if runtime_truth else None
    runtime_can_execute_today = bool(runtime_truth.get("trading_ready")) if runtime_truth else None
    runtime_blocking_reason = str(
        runtime_truth.get("trading_status_reason")
        or runtime_truth.get("state_reason")
        or runtime_payload.get("halt_reason")
        or ""
    )

    issues: list[dict[str, Any]] = []

    drawdown_pct = parse_float(metrics.get("max_drawdown_pct"), 0.0)
    if drawdown_pct > parse_float(thresholds.get("paper_max_drawdown_pct"), 8.0):
        issues.append({"level": "RED", "code": "MAX_DRAWDOWN_BREACH", "value": drawdown_pct, "limit": thresholds.get("paper_max_drawdown_pct")})

    daily_ret_raw = journal_df.get("pnl_day")
    if daily_ret_raw is None:
        daily_ret = pd.Series([], dtype=float)
    elif isinstance(daily_ret_raw, (int, float)):
        daily_ret = pd.Series([daily_ret_raw])
    else:
        daily_ret = pd.to_numeric(daily_ret_raw, errors="coerce").fillna(0.0)
    nav = parse_float(account_payload.get("nav"), 0.0)
    if nav > 0 and len(daily_ret) > 0:
        ret_series = daily_ret.tail(20) / nav
    else:
        ret_series = pd.Series(dtype=float)

    trailing_20d_ret = trailing_return_pct(ret_series)
    if trailing_20d_ret < parse_float(thresholds.get("paper_20d_return_floor_pct"), -5.0):
        issues.append({"level": "RED", "code": "RET_20D_BREACH", "value": trailing_20d_ret, "limit": thresholds.get("paper_20d_return_floor_pct")})

    trailing_20d_sharpe = round(annualized_sharpe(ret_series.tail(20)), 3) if not ret_series.empty else 0.0
    if trailing_20d_sharpe < parse_float(thresholds.get("paper_20d_sharpe_floor"), 0.0):
        issues.append({"level": "YELLOW", "code": "SHARPE_20D_BREACH", "value": trailing_20d_sharpe, "limit": thresholds.get("paper_20d_sharpe_floor")})

    avg_slippage = round(float(pd.to_numeric(journal_df.get("slippage"), errors="coerce").fillna(0.0).mean()), 2) if not journal_df.empty else 0.0
    if avg_slippage > parse_float(thresholds.get("paper_avg_slippage_cap"), 200.0):
        issues.append({"level": "YELLOW", "code": "AVG_SLIPPAGE_BREACH", "value": avg_slippage, "limit": thresholds.get("paper_avg_slippage_cap")})

    turnover_col = "weight_after"
    avg_turnover = 0.0
    if turnover_col in journal_df.columns and not journal_df.empty:
        avg_turnover = round(float(pd.to_numeric(journal_df.get(turnover_col), errors="coerce").diff().abs().fillna(0.0).mean()), 4)
    if avg_turnover > parse_float(thresholds.get("paper_avg_turnover_cap"), 0.12):
        issues.append({"level": "YELLOW", "code": "AVG_TURNOVER_BREACH", "value": avg_turnover, "limit": thresholds.get("paper_avg_turnover_cap")})

    journal_records = int(len(journal_df))
    runtime_halt_blocked_orders = False
    if journal_records <= int(parse_float(thresholds.get("paper_missing_journal_records_cap"), 1.0)) and positions_df.empty:
        if not orders_df.empty:
            runtime_halt_blocked_orders = (
                bool(runtime_truth)
                and runtime_buy_authorized is False
                and runtime_trading_status in {"BUY_HALT", "FULL_HALT"}
            )
            if runtime_halt_blocked_orders:
                issues.append(
                    {
                        "level": "INFO",
                        "code": "PLANNED_ORDERS_BLOCKED_BY_RUNTIME_HALT",
                        "value": int(len(orders_df)),
                        "limit": 0,
                    }
                )
            elif runtime_truth and runtime_truth.get("trading_status") in {"TRADING", "RISK_OFF", "CAUTIOUS"}:
                # T05 fix: per-panel halt=False, today is non-trading day with pending orders
                # from previous session → normal no-activity, not an error
                issues.append({"level": "YELLOW", "code": "NO_ACTIVITY_DAY", "value": journal_records, "limit": thresholds.get("paper_missing_journal_records_cap")})
            else:
                issues.append({"level": "RED", "code": "NO_JOURNAL_WITH_PLANNED_ORDERS", "value": int(len(orders_df)), "limit": 0})
        else:
            issues.append({"level": "YELLOW", "code": "NO_ACTIVITY_DAY", "value": journal_records, "limit": thresholds.get("paper_missing_journal_records_cap")})

    error_trade_count = int(journal_df.get("risk_reason", pd.Series(dtype=str)).astype(str).str.contains("error|reject|failed", case=False, na=False).sum()) if not journal_df.empty else 0
    if error_trade_count > int(parse_float(thresholds.get("paper_error_trade_count_cap"), 0.0)):
        issues.append({"level": "RED", "code": "ERROR_TRADE_COUNT_BREACH", "value": error_trade_count, "limit": thresholds.get("paper_error_trade_count_cap")})

    observation_days = int(cfg.get("admission", {}).get("paper_observation_min_days", 20))
    status = "GREEN"
    tomorrow_mode = "normal"
    if any(item["level"] == "RED" for item in issues):
        status = "RED"
        tomorrow_mode = "halt"
    elif any(item["level"] == "YELLOW" for item in issues):
        status = "YELLOW"
        tomorrow_mode = "cautious"
    elif runtime_halt_blocked_orders:
        status = "GREEN"
        tomorrow_mode = "observe"
    elif journal_records < observation_days:
        # Journal 不足 observation_days 天数，但不构成告警；次日模式改为 observe
        status = "GREEN"
        tomorrow_mode = "observe"

    payload = {
        "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "config": str(cfg_path),
        "date_tag": date_tag,
        "profile_slug": profile_slug,
        "status": status,
        "tomorrow_mode": tomorrow_mode,
        "issues": issues,
        "runtime_truth": {
            "source_path": str(runtime_state_path),
            "state": runtime_truth_state or None,
            "trading_status": runtime_trading_status or None,
            "can_execute_today": runtime_can_execute_today,
            "buy_authorized": runtime_buy_authorized,
            "blocking_reason": runtime_blocking_reason or None,
        },
        "inputs": {
            "journal": str(journal_path),
            "orders": str(orders_path),
            "account": str(account_path),
            "metrics": str(metrics_path),
            "positions": str(positions_path),
            "runtime_risk_state": str(runtime_state_path),
        },
        "stats": {
            "nav": round(nav, 2),
            "planned_orders": int(len(orders_df)),
            "journal_records": journal_records,
            "position_count": int(account_payload.get("position_count", len(positions_df)) or 0),
            "max_drawdown_pct": drawdown_pct,
            "trailing_20d_return_pct": trailing_20d_ret,
            "trailing_20d_sharpe": trailing_20d_sharpe,
            "avg_slippage": avg_slippage,
            "avg_turnover_proxy": avg_turnover,
            "error_trade_count": error_trade_count,
        },
    }

    out_json = REPORT_DIR / f"paper_{profile_slug + '_' if profile_slug else ''}probe_guard_{date_tag}.json"
    out_md = REPORT_DIR / f"paper_{profile_slug + '_' if profile_slug else ''}probe_guard_{date_tag}.md"
    out_latest = REPORT_DIR / f"paper_{profile_slug + '_' if profile_slug else ''}probe_guard_latest.json"
    out_json.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    out_latest.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")

    md_lines = [
        f"# 模拟盘/探针仓守卫结果（{date_tag}）",
        "",
        f"- 状态: `{status}`",
        f"- 次日模式: `{tomorrow_mode}`",
        f"- 净值: `{payload['stats']['nav']}`",
        f"- 日志记录数: `{journal_records}`",
        f"- 最大回撤: `{drawdown_pct}%`",
        f"- 近20日收益: `{trailing_20d_ret}%`",
        f"- 近20日Sharpe: `{trailing_20d_sharpe}`",
        f"- 平均滑点: `{avg_slippage}`",
        f"- 平均换手代理: `{avg_turnover}`",
        f"- 异常成交数: `{error_trade_count}`",
        f"- 统一执行状态: `{runtime_truth_state or '-'}` / trading_status=`{runtime_trading_status or '-'}` / can_execute_today=`{runtime_can_execute_today}` / buy_authorized=`{runtime_buy_authorized}`",
        f"- 统一阻断原因: `{runtime_blocking_reason or '-'}`",
        "",
        "## Issues",
    ]
    if issues:
        for item in issues:
            md_lines.append(f"- [{item['level']}] `{item['code']}` value=`{item['value']}` limit=`{item['limit']}`")
    else:
        md_lines.append("- 无触发项")
    out_md.write_text("\n".join(md_lines) + "\n", encoding="utf-8")

    if args.push and status in {"RED", "YELLOW"}:
        msg = "\n".join(
            [
                f"策略守卫告警｜{date_tag}｜{profile_slug or 'default'}",
                f"状态: {status}",
                f"次日模式: {tomorrow_mode}",
                f"最大回撤: {drawdown_pct}%",
                f"近20日收益: {trailing_20d_ret}%",
                f"近20日Sharpe: {trailing_20d_sharpe}",
                f"平均滑点: {avg_slippage}",
                f"Issues: {', '.join(item['code'] for item in issues) if issues else 'none'}",
                f"报告: {out_md}",
            ]
        )
        ok, detail = push_feishu(cfg, msg)
        payload["push"] = {"ok": ok, "detail": detail}
        out_json.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        out_latest.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")

    print(json.dumps({"status": status, "tomorrow_mode": tomorrow_mode, "report_json": str(out_json), "report_md": str(out_md)}, ensure_ascii=False, indent=2))


