from __future__ import annotations

import re
from pathlib import Path
from typing import Any


def profile_slug_from_config(cfg: dict[str, Any]) -> str:
    raw = str(cfg.get("profile_slug", "") or cfg.get("profile", "") or "").strip().lower()
    if not raw:
        return ""
    slug = re.sub(r"[^a-z0-9]+", "_", raw)
    return slug.strip("_")


def profile_name_from_config(cfg: dict[str, Any]) -> str:
    explicit = str(cfg.get("profile_name", "") or "").strip()
    if explicit:
        return explicit
    slug = profile_slug_from_config(cfg)
    return slug or "default"


def _profile_prefix(profile_slug: str) -> str:
    return f"{profile_slug}_" if profile_slug else ""


def report_filename(kind: str, profile_slug: str = "", date_tag: str = "") -> str:
    prefix = _profile_prefix(profile_slug)
    mapping = {
        "orders": f"paper_{prefix}orders_v1_{date_tag}.csv",
        "order_plan": f"paper_{prefix}order_plan_v1_{date_tag}.json",
        "order_diagnostics_json": f"paper_{prefix}order_diagnostics_v1_{date_tag}.json",
        "order_diagnostics_md": f"paper_{prefix}order_diagnostics_v1_{date_tag}.md",
        "execution_brief": f"paper_{prefix}execution_brief_v1_{date_tag}.md",
        "execution_holdings_dated": f"paper_{prefix}execution_holdings_{date_tag}.csv",
        "execution_holdings_latest": f"paper_{prefix}execution_holdings_latest.csv",
        "journal": f"paper_{prefix}trading_journal_{date_tag}.csv",
        "summary": f"paper_{prefix}trading_summary_v1_{date_tag}.md",
        "positions_dated": f"paper_{prefix}portfolio_positions_{date_tag}.csv",
        "positions_latest": f"paper_{prefix}portfolio_positions_latest.csv",
        "nav_curve": f"paper_{prefix}nav_curve_v1.csv",
        "account_dated": f"paper_{prefix}account_v1_{date_tag}.json",
        "account_latest": f"paper_{prefix}account_v1_latest.json",
        "dashboard_dated": f"paper_{prefix}trading_dashboard_{date_tag}.html",
        "dashboard_latest": f"paper_{prefix}trading_dashboard_latest.html",
        "metrics": f"paper_{prefix}trading_metrics_{date_tag}.json",
        "comparison_dashboard_dated": f"paper_profiles_comparison_{date_tag}.html",
        "comparison_dashboard_latest": "paper_profiles_comparison_latest.html",
        "comparison_metrics": f"paper_profiles_comparison_metrics_{date_tag}.json",
    }
    if kind not in mapping:
        raise KeyError(f"未知 paper report kind: {kind}")
    return mapping[kind]


def report_path(report_dir: Path, kind: str, profile_slug: str = "", date_tag: str = "") -> Path:
    return report_dir / report_filename(kind=kind, profile_slug=profile_slug, date_tag=date_tag)


def config_positions_file(project_root: Path, profile_slug: str = "") -> Path:
    prefix = _profile_prefix(profile_slug)
    return project_root / "config" / f"paper_{prefix}portfolio_positions.csv"


def journal_glob(profile_slug: str = "") -> str:
    return report_filename("journal", profile_slug=profile_slug, date_tag="*")


def account_glob(profile_slug: str = "") -> str:
    return report_filename("account_dated", profile_slug=profile_slug, date_tag="*")


def orders_glob(profile_slug: str = "") -> str:
    return report_filename("orders", profile_slug=profile_slug, date_tag="*")

