import incident_registry as incident_registry_mod

ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / "research" / "reports"
WORKSPACE = Path("/Users/ling/.openclaw/workspace")
HEARTBEAT_PATH = WORKSPACE / "HEARTBEAT.md"
LIVE_EXEC_PATH = ROOT / "scripts" / "run_live_execution_v1.py"
SCHEDULER_CONFIG_PATH = ROOT / "config" / "live_scheduler_v1.json"
PROFILE_SLUGS = ("defensive", "balanced", "aggressive")
ARTIFACT_MAX_AGE = timedelta(days=4)
OBSERVE_WINDOW = timedelta(days=4)


@dataclass
class AuditResult:
    date_tag: str
    annual_return_pct: float
    max_drawdown_pct: float
    sharpe: float
    robust_pass: bool
    target_hit: bool
    strategy_health_status: str
    precheck_status: str
