    governance_status: dict[str, Any]
    incident_status: dict[str, Any]
    intervention_status: dict[str, Any]
    blocking_issues: list[str]


def latest_file(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern), key=lambda p: p.stat().st_mtime, reverse=True)
    return files[0] if files else None


def load_json(path: Path | None) -> dict[str, Any]:
    if path is None or not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def is_operational_precheck_status(status: str) -> bool:
    return status in {"ok", "risk_off", "risk_halt", "no_signal"}


def extract_date_tag(path: Path | None) -> str:
    if path is None:
        return ""
    stem = path.stem
    for part in reversed(stem.split("_")):
        if len(part) == 8 and part.isdigit():
            return part
    return ""


def is_recent_date_tag(date_tag: str, now: datetime) -> bool:
    if not date_tag:
        return False
    try:
        dt = datetime.strptime(date_tag, "%Y%m%d")
    except ValueError:
        return False
    return (now - dt) <= ARTIFACT_MAX_AGE


def is_recent_mtime(path: Path | None, now: datetime, max_age: timedelta = ARTIFACT_MAX_AGE) -> bool:
    if path is None or not path.exists():
        return False
    mtime = datetime.fromtimestamp(path.stat().st_mtime)
    return (now - mtime) <= max_age


def load_csv_rows(path: Path | None) -> list[dict[str, Any]]:
    if path is None or not path.exists():
        return []
    with path.open("r", encoding="utf-8-sig", newline="") as f:
        return list(csv.DictReader(f))


def _is_blank(value: Any) -> bool:
    text = str(value or "").strip()
    return text == "" or text.lower() == "nan"


def manual_review_status(profile_slug: str, now: datetime) -> dict[str, Any]:
    recon_path = latest_file(f"paper_{profile_slug}_daily_reconciliation_*.csv")
    if recon_path is None:
        return {
            "profile_slug": profile_slug,
            "completed": False,
            "issues": ["missing_reconciliation"],
            "path": None,
        }
    if not is_recent_mtime(recon_path, now):
        return {
            "profile_slug": profile_slug,
            "completed": False,
            "issues": ["stale_reconciliation"],
            "path": str(recon_path),
        }

    rows = load_csv_rows(recon_path)
    if not rows:
        return {
            "profile_slug": profile_slug,
            "completed": False,
            "issues": ["empty_reconciliation"],
            "path": str(recon_path),
        }

    pending_items: list[str] = []
    reviewer = ""
    for row in rows:
        section = str(row.get("section") or "").strip()
        item = str(row.get("item") or "").strip()
        if section not in {"人工复核", "结论"}:
            continue
        value = str(row.get("value") or "").strip()
        status = str(row.get("status") or "").strip().upper()
        if item == "复核人" and (not _is_blank(value)):
            reviewer = value
        if status in {"", "TODO", "AUTO"} or _is_blank(value):
            pending_items.append(item or "unknown")

    issues = [f"pending_manual_review:{item}" for item in pending_items]
    if not reviewer:
        issues.append("missing_reviewer")
    return {
        "profile_slug": profile_slug,
        "completed": len(pending_items) == 0 and bool(reviewer),
        "issues": issues,
        "path": str(recon_path),
        "reviewer": reviewer,
    }


def profile_runtime_status(profile_slug: str, now: datetime) -> dict[str, Any]:
    prefix = f"paper_{profile_slug}"
    account_latest = REPORT_DIR / f"{prefix}_account_v1_latest.json"
    positions_latest = REPORT_DIR / f"{prefix}_portfolio_positions_latest.csv"
    orders_path = latest_file(f"{prefix}_orders_v1_*.csv")
    tickets_path = latest_file(f"{prefix}_signal_tickets_*.csv")
    journal_path = latest_file(f"{prefix}_trading_journal_*.csv")
    order_plan_path = latest_file(f"{prefix}_order_plan_v1_*.json")

    dated_tags = {
        "orders": extract_date_tag(orders_path),
        "tickets": extract_date_tag(tickets_path),
        "journal": extract_date_tag(journal_path),
        "order_plan": extract_date_tag(order_plan_path),
    }
    unique_tags = sorted({value for value in dated_tags.values() if value})
    profile_date_tag = unique_tags[0] if len(unique_tags) == 1 else ""

    issues: list[str] = []
    if not account_latest.exists():
        issues.append("missing_account_latest")
    elif not is_recent_mtime(account_latest, now):
        issues.append("stale_account_latest")
    if not positions_latest.exists():
        issues.append("missing_positions_latest")
    elif not is_recent_mtime(positions_latest, now):
        issues.append("stale_positions_latest")
    for kind, path in {
        "orders": orders_path,
        "tickets": tickets_path,
        "journal": journal_path,
        "order_plan": order_plan_path,
    }.items():
        if path is None:
            issues.append(f"missing_{kind}")
    if len(unique_tags) > 1:
        issues.append("dated_artifact_tag_mismatch")
    elif not profile_date_tag:
        issues.append("missing_profile_date_tag")
    elif not is_recent_date_tag(profile_date_tag, now):
        issues.append("stale_profile_date_tag")

    return {
        "profile_slug": profile_slug,
        "date_tag": profile_date_tag,
        "runtime_ready": not issues,
        "issues": issues,
        "artifacts": {
            "account_latest": str(account_latest) if account_latest.exists() else None,
            "positions_latest": str(positions_latest) if positions_latest.exists() else None,
            "orders": str(orders_path) if orders_path else None,
            "tickets": str(tickets_path) if tickets_path else None,
            "journal": str(journal_path) if journal_path else None,
            "order_plan": str(order_plan_path) if order_plan_path else None,
        },
        "dated_tags": dated_tags,
