#!/usr/bin/env python3
from __future__ import annotations

import html
import json
from datetime import datetime
from pathlib import Path
from typing import Any

import pandas as pd

from panel_profile_registry import (  # type: ignore
    BREADTH_PROFILE_SPECS,
    CURRENT_PAPER_PROFILE_SPECS,
    CURRENT_PAPER_SLUGS,
    GROUP_ORDER,
    LEGACY_PAPER_PROFILE_SPECS,
    LEGACY_PAPER_SLUGS,
    strategy_profile_spec,
)

PROJECT_ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = PROJECT_ROOT / "research" / "reports"
PROFILE_ORDER = {
    spec["slug"]: index
    for index, spec in enumerate(CURRENT_PAPER_PROFILE_SPECS + BREADTH_PROFILE_SPECS + LEGACY_PAPER_PROFILE_SPECS)
}
STATUS_ORDER = {"RED": 0, "YELLOW": 1, "GREEN": 2, "NO_DATA": 3}


def load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def load_curve_tail(path: Path) -> pd.DataFrame:
    if not path.exists():
        return pd.DataFrame()
    try:
        df = pd.read_csv(path)
    except Exception:
        return pd.DataFrame()
    if df.empty:
        return df
    return df.tail(60).copy()


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def file_age_hours(path: Path | None) -> float | None:
    if not path or not path.exists():
        return None
    return max((datetime.now() - datetime.fromtimestamp(path.stat().st_mtime)).total_seconds() / 3600.0, 0.0)


def freshness_label(age_hours: float | None, *, stale_hours: int = 24) -> tuple[str, bool]:
    if age_hours is None:
        return "缺失", True
    if age_hours > stale_hours:
        return f"停更 {age_hours:.1f}h", True
    return f"正常 {age_hours:.1f}h", False


def apply_stale_override(status: str, status_label: str, reasons: list[str], age_hours: float | None) -> tuple[str, str, list[str]]:
    _, is_stale = freshness_label(age_hours)
    if not is_stale:
        return status, status_label, reasons
    reasons = list(reasons)
    reasons.append("stale_file")
    if status == "GREEN":
        return "YELLOW", "STALE", reasons
    if status == "NO_DATA" and status_label == "LEGACY":
        return status, status_label, reasons
    return status, status_label, reasons


def infer_account_status(profile_slug: str, account: dict[str, Any], guard: dict[str, Any]) -> tuple[str, str, list[str]]:
    if not account:
        return "NO_DATA", "NO_DATA", ["missing_account"]

    guard_status = str(guard.get("status") or "").strip().upper()
    if guard_status in STATUS_ORDER:
        reasons = [str(item.get("code") or "").strip() for item in (guard.get("issues") or []) if str(item.get("code") or "").strip()]
        return guard_status, guard_status, reasons

    if profile_slug in CURRENT_PAPER_SLUGS:
        return "YELLOW", "UNGUARDED", ["missing_probe_guard"]
    if profile_slug in LEGACY_PAPER_SLUGS:
        return "NO_DATA", "LEGACY", ["legacy_profile"]
    return "NO_DATA", "NO_DATA", ["missing_guard"]


def build_curve_points(curve: pd.DataFrame, account: dict[str, Any]) -> list[dict[str, Any]]:
    curve_points: list[dict[str, Any]] = []
    if not curve.empty:
        for _, row in curve.iterrows():
            curve_points.append(
                {
                    "date": str(row.get("date", row.get("date_tag", ""))),
                    "nav": parse_float(row.get("nav"), 0.0),
                    "drawdown_pct": parse_float(row.get("drawdown_pct"), 0.0),
                }
            )
        return curve_points

    latest_nav = parse_float(account.get("nav"), 0.0)
    initial_cash = parse_float(account.get("initial_cash"), 0.0)
    remaining_cash = parse_float(account.get("remaining_cash"), 0.0)
    total_cost = parse_float(account.get("total_cost"), 0.0)
    fallback_nav = latest_nav or (remaining_cash + total_cost)
    if fallback_nav <= 0 and initial_cash > 0:
        fallback_nav = initial_cash
    if fallback_nav <= 0:
        return []
    return [
        {
            "date": str(account.get("trade_date") or account.get("date_tag") or ""),
            "nav": fallback_nav,
            "drawdown_pct": parse_float(account.get("drawdown_pct"), 0.0),
        }
    ]


def build_account_row(profile_slug: str) -> dict[str, Any] | None:
    spec = strategy_profile_spec(profile_slug)
    account_path = REPORT_DIR / f"paper_{profile_slug}_account_v1_latest.json"
    account = load_json(account_path)
    if not account:
        return None

    guard_path = REPORT_DIR / f"paper_{profile_slug}_probe_guard_latest.json"
    guard = load_json(guard_path)
    curve = load_curve_tail(REPORT_DIR / f"paper_{profile_slug}_nav_curve_v1.csv")
    age_hours = file_age_hours(account_path)

    initial_cash = parse_float(account.get("initial_cash"), 0.0)
    latest_nav = parse_float(account.get("nav"), 0.0)
    remaining_cash = parse_float(account.get("remaining_cash"), 0.0)
    total_cost = parse_float(account.get("total_cost"), 0.0)
    if latest_nav <= 0:
        latest_nav = remaining_cash + total_cost
    if latest_nav <= 0 and initial_cash > 0:
        latest_nav = initial_cash

    cash = parse_float(account.get("cash"), 0.0)
    if cash <= 0:
        cash = remaining_cash
    market_value = parse_float(account.get("market_value"), 0.0)
    if market_value <= 0:
        market_value = total_cost

    positions = int(account.get("position_count", 0) or len(account.get("positions", []) or []))
    today_trade_count = int(account.get("today_trade_count", 0) or len(account.get("orders", []) or []))
    total_return_pct = round((latest_nav / initial_cash - 1.0) * 100.0, 2) if initial_cash > 0 else parse_float(account.get("total_return_pct"), 0.0)

    status, status_label, reasons = infer_account_status(profile_slug, account, guard)
    status, status_label, reasons = apply_stale_override(status, status_label, reasons, age_hours)
    freshness_text, _ = freshness_label(age_hours)

    display_name = str(account.get("profile_name") or "").strip()
    if not display_name or display_name.lower() == profile_slug.lower():
        fallback_name = str(account.get("name") or "").strip()
        display_name = fallback_name if fallback_name and fallback_name.lower() != profile_slug.lower() else str(spec["name"])

    return {
        "group": spec["group"],
        "group_label": spec["group_label"],
        "profile_slug": str(account.get("profile_slug") or profile_slug),
        "profile_name": display_name,
        "short_name": str(spec.get("short_name") or spec["name"]),
        "date_tag": str(account.get("date_tag") or account.get("trade_date") or ""),
        "status": status,
        "status_label": status_label,
        "tomorrow_mode": str(guard.get("tomorrow_mode") or ("legacy" if profile_slug in LEGACY_PAPER_SLUGS else "paper_only")),
        "nav": round(latest_nav, 2),
        "total_return_pct": total_return_pct,
        "day_pnl": round(parse_float(account.get("day_pnl"), 0.0), 2),
        "drawdown_pct": round(parse_float(account.get("drawdown_pct"), total_return_pct), 2),
        "cash": round(cash, 2),
        "market_value": round(market_value, 2),
        "position_count": positions,
        "today_trade_count": today_trade_count,
        "issue_codes": ",".join(reasons) if reasons else "none",
        "curve": build_curve_points(curve, account),
        "freshness": freshness_text,
        "file_updated_at": datetime.fromtimestamp(account_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if account_path.exists() else "-",
        "status_reason": ", ".join(reasons) if reasons else "ok",
        "guard_present": guard_path.exists(),
    }


def build_breadth_row(profile_slug: str) -> dict[str, Any] | None:
    spec = strategy_profile_spec(profile_slug)
    summary_path = REPORT_DIR / f"{profile_slug}_paper_latest.json"
    breadth_summary = load_json(summary_path)
    if not breadth_summary:
        return None

    paper_capital = parse_float(breadth_summary.get("paper_capital"), 0.0)
    latest_nav_ratio = parse_float(breadth_summary.get("nav"), 0.0)
    latest_total_value = parse_float(breadth_summary.get("total_value"), 0.0)
    if latest_total_value <= 0 and paper_capital > 0 and latest_nav_ratio > 0:
        latest_total_value = latest_nav_ratio * paper_capital
    if latest_total_value <= 0:
        latest_total_value = parse_float(breadth_summary.get("cash"), 0.0) + parse_float(breadth_summary.get("market_value"), 0.0)

    breadth_curve: list[dict[str, Any]] = []
    peak_nav_ratio = 0.0
    latest_drawdown_pct = 0.0
    prev_total_value = None
    day_pnl = 0.0
    for item in breadth_summary.get("nav_history", []) or []:
        nav_ratio = parse_float(item.get("nav"), 0.0)
        if nav_ratio <= 0:
            continue
        peak_nav_ratio = max(peak_nav_ratio, nav_ratio)
        latest_drawdown_pct = round((nav_ratio / peak_nav_ratio - 1.0) * 100.0, 2) if peak_nav_ratio > 0 else 0.0
        total_value = nav_ratio * paper_capital if paper_capital > 0 else nav_ratio
        if prev_total_value is not None:
            day_pnl = round(total_value - prev_total_value, 2)
        prev_total_value = total_value
        breadth_curve.append(
            {
                "date": str(item.get("date", "")),
                "nav": round(total_value, 2),
                "drawdown_pct": latest_drawdown_pct,
            }
        )

    total_return_pct = round((latest_nav_ratio - 1.0) * 100.0, 2) if latest_nav_ratio > 0 else 0.0
    reasons: list[str] = []
    detail_parts: list[str] = []
    status = "GREEN"
    status_label = "GREEN"

